## 3. 데이터 모델 (TypeScript)

```typescript
// src/types/index.ts

export type Priority = 'P1' | 'P2' | 'P3';

export type TaskStatus = 'todo' | 'in_progress' | 'blocked' | 'done';

export interface Project {
  id: string;
  name: string;
  color: string;      // hex color e.g. '#4F6EF7'
  createdAt: string;  // ISO string
}

export interface Task {
  id: string;
  projectId: string | null;   // null = Inbox (미분류)
  title: string;
  status: TaskStatus;
  priority: Priority;
  dueDate: string | null;     // 'YYYY-MM-DD' format
  tags: string[];
  memo: string;               // 자유 메모 (옵션)
  createdAt: string;          // ISO string
  updatedAt: string;          // ISO string
}

// 뷰 필터 타입
export type ViewFilter =
  | { type: 'all' }
  | { type: 'project'; projectId: string }
  | { type: 'today' }
  | { type: 'urgent' };       // P1 필터

// 앱 전역 상태
export interface AppState {
  projects: Project[];
  tasks: Task[];
  activeFilter: ViewFilter;
  showDoneTasks: boolean;
}
```

---

## 4. 상태 관리 설계

### 4.1 Reducer 액션 정의

```typescript
// src/store/actions.ts

export const ACTIONS = {
  // Task
  ADD_TASK: 'ADD_TASK',
  UPDATE_TASK: 'UPDATE_TASK',
  DELETE_TASK: 'DELETE_TASK',
  TOGGLE_TASK_DONE: 'TOGGLE_TASK_DONE',

  // Project
  ADD_PROJECT: 'ADD_PROJECT',
  UPDATE_PROJECT: 'UPDATE_PROJECT',
  DELETE_PROJECT: 'DELETE_PROJECT',

  // UI
  SET_FILTER: 'SET_FILTER',
  TOGGLE_SHOW_DONE: 'TOGGLE_SHOW_DONE',

  // Storage
  LOAD_FROM_STORAGE: 'LOAD_FROM_STORAGE',
} as const;
```

### 4.2 Reducer 핵심 로직

```typescript
// src/store/reducer.ts

export function appReducer(state: AppState, action: AppAction): AppState {
  switch (action.type) {

    case ACTIONS.ADD_TASK: {
      const newTask: Task = {
        id: crypto.randomUUID(),
        ...action.payload,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };
      return { ...state, tasks: [newTask, ...state.tasks] };
    }

    case ACTIONS.UPDATE_TASK: {
      return {
        ...state,
        tasks: state.tasks.map(t =>
          t.id === action.payload.id
            ? { ...t, ...action.payload, updatedAt: new Date().toISOString() }
            : t
        ),
      };
    }

    case ACTIONS.DELETE_TASK:
      return { ...state, tasks: state.tasks.filter(t => t.id !== action.payload.id) };

    case ACTIONS.TOGGLE_TASK_DONE: {
      return {
        ...state,
        tasks: state.tasks.map(t =>
          t.id === action.payload.id
            ? { ...t, status: t.status === 'done' ? 'todo' : 'done', updatedAt: new Date().toISOString() }
            : t
        ),
      };
    }

    case ACTIONS.ADD_PROJECT: {
      const newProject: Project = {
        id: crypto.randomUUID(),
        ...action.payload,
        createdAt: new Date().toISOString(),
      };
      return { ...state, projects: [...state.projects, newProject] };
    }

    case ACTIONS.SET_FILTER:
      return { ...state, activeFilter: action.payload };

    case ACTIONS.TOGGLE_SHOW_DONE:
      return { ...state, showDoneTasks: !state.showDoneTasks };

    case ACTIONS.LOAD_FROM_STORAGE:
      return { ...state, ...action.payload };

    default:
      return state;
  }
}
```

### 4.3 Context + localStorage 연동

```typescript
// src/store/AppContext.tsx (핵심 패턴)

const STORAGE_KEY = 'pm_task_manager_v1';

export function AppProvider({ children }: { children: ReactNode }) {
  const [state, dispatch] = useReducer(appReducer, initialState);

  // 앱 마운트 시 localStorage에서 불러오기
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        dispatch({ type: ACTIONS.LOAD_FROM_STORAGE, payload: parsed });
      } catch (e) {
        console.error('Storage parse error:', e);
      }
    }
  }, []);

  // 상태 변경 시 localStorage에 저장 (tasks, projects만)
  useEffect(() => {
    const toSave = {
      projects: state.projects,
      tasks: state.tasks,
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(toSave));
  }, [state.projects, state.tasks]);

  return (
    <AppContext.Provider value={{ state, dispatch }}>
      {children}
    </AppContext.Provider>
  );
}
```

